DROP TABLE IF EXISTS `carritos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `carritos` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `sesion_id` int unsigned DEFAULT NULL,
  `divisa_id` int unsigned NOT NULL DEFAULT '1',
  `total_productos` int unsigned NOT NULL DEFAULT '0',
  `monto_aproximado` double unsigned NOT NULL DEFAULT '0',
  `fecha_creacion` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `fecha_actualizacion` datetime DEFAULT NULL,
  `estatus` enum('Abandonado','Cancelado','Activo','Convertido','Expirado') NOT NULL DEFAULT 'Activo',
  PRIMARY KEY (`id`),
  KEY `fk_divisa_idx` (`divisa_id`),
  KEY `fk_sesion_idx` (`sesion_id`),
  CONSTRAINT `fk_divisa` FOREIGN KEY (`divisa_id`) REFERENCES `divisas` (`id`),
  CONSTRAINT `fk_sesion` FOREIGN KEY (`sesion_id`) REFERENCES `sesiones` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1002 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
