  `capacidad_juridica` varchar(100) DEFAULT NULL,
  `patrimonio` varchar(100) DEFAULT NULL,
  UNIQUE KEY `id_UNIQUE` (`id`),
  CONSTRAINT `fk_persona_moral` FOREIGN KEY (`id`) REFERENCES `personas` (`id`)
