DROP TABLE IF EXISTS `productos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `productos` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `nombre` varchar(150) NOT NULL,
  `descripcion` text,
  `marca` varchar(100) NOT NULL,
  `modelo` varchar(100) DEFAULT NULL,
  `precio_menudeo` decimal(10,2) NOT NULL DEFAULT '0.00',
  `precio_mayoreo` decimal(10,2) DEFAULT NULL,
  `tipo` enum('Perecedero','No Perecedero') NOT NULL DEFAULT 'No Perecedero',
  `estatus` enum('Activo','Agotado','En existencia','Descontinuado','Baja existencia') NOT NULL DEFAULT 'Activo',
  `codigo_barras` varchar(40) NOT NULL,
  `sku` varchar(40) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `codigo_barras` (`codigo_barras`),
  UNIQUE KEY `sku` (`sku`)
) ENGINE=InnoDB AUTO_INCREMENT=501 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
