CREATE TABLE `proveedores` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `persona_id` int unsigned NOT NULL,
  `tipo` enum('Mayoreo','Menudeo','Mixto') NOT NULL DEFAULT 'Menudeo',
  `estatus` enum('Activo','Inactivo','Bloqueado','No vigente') NOT NULL DEFAULT 'Activo',
  `fecha_registro` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `total_productos` int NOT NULL DEFAULT '0',
  `monto_acumulado` float NOT NULL DEFAULT '0',
  `fecha_ultima_compra` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_proveedpr_idx` (`persona_id`),
  CONSTRAINT `fk_proveedpr` FOREIGN KEY (`persona_id`) REFERENCES `personas` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=725 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
