  `estatus` enum('Activa','Finalizada','Cancelada','Suspendida') NOT NULL DEFAULT 'Activa',
  PRIMARY KEY (`id`),
  KEY `fk_usuarios1_idx` (`usuario_id`),
  CONSTRAINT `fk_usuarios1` FOREIGN KEY (`usuario_id`) REFERENCES `usuarios` (`persona_fisica_id`),
  CONSTRAINT `chk_fechas` CHECK ((`fecha_inicio` >= `fecha_registro`))
