DROP TABLE IF EXISTS `transacciones_financieras`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `transacciones_financieras` (
  `id` int(10) unsigned zerofill NOT NULL AUTO_INCREMENT,
  `tipo` enum('Compra','Venta','Salario','Reembolso') NOT NULL,
  `origen` enum('Tarjeta de Débito','Tarjeta de Crédito','Transferencia Bancaria','Socio Comercial','Tarjeta de Regalo','Créditos Devolución','Vales Despensa') NOT NULL,
  `clave_interbancaria` char(18) DEFAULT NULL,
  `numero_convenio` varchar(50) DEFAULT NULL,
  `monto` decimal(10,2) NOT NULL DEFAULT '0.00',
  `metodo_pago_id` int(10) unsigned zerofill DEFAULT NULL,
  `estatus` enum('Aprobado','No Aprobado','Pendiente','Cancelado') DEFAULT NULL,
  `fecha_registro` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `fecha_actualizacion` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_metodopago_idx` (`metodo_pago_id`),
  CONSTRAINT `fk_metodopago` FOREIGN KEY (`metodo_pago_id`) REFERENCES `metodos_pago` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='\n';
