CREATE DEFINER=`root`@`localhost` FUNCTION `calcula_antiguedad`(v_fecha_registro DATE) RETURNS int
    DETERMINISTIC
BEGIN
       
RETURN floor(datediff(NOW(),v_fecha_nacimiento)/365.25);
END ;;
