CREATE DEFINER=`root`@`localhost` FUNCTION `elige_cantidad`() RETURNS int
    DETERMINISTIC
BEGIN
    DECLARE v_random INT;

    SET v_random = genera_numero_aleatorio_rangos(1, 1000);

    RETURN CASE
        WHEN v_random <= 820 THEN 1          -- 82.0%
        WHEN v_random <= 940 THEN 2          -- 12.0%
        WHEN v_random <= 980 THEN 3          -- 4.0%
        WHEN v_random <= 995 THEN 4          -- 1.5%
        ELSE 5                               -- 0.5%
    END;
END ;;
