DELIMITER ;;
CREATE DEFINER=`root`@`localhost` FUNCTION `genera_fechahora_lapso`(p_fecha_base DATETIME, p_tipo VARCHAR(20)) RETURNS datetime
    NO SQL
BEGIN
    DECLARE v_roll INT;
    DECLARE v_lapso_seg INT DEFAULT 0;
    DECLARE v_result DATETIME;

    -- Normalizar tipo
    SET p_tipo = LOWER(TRIM(p_tipo));

    /* -------------------------
       TIPO: DEMORA (1..100)
       70%: 0s
       20%: 10-60s
       10%: 61-300s
       ------------------------- */
    IF p_tipo = 'demora' THEN
        SET v_roll = genera_numero_aleatorio_rangos(1, 100);

        IF v_roll <= 70 THEN
            SET v_lapso_seg = 0;
        ELSEIF v_roll <= 90 THEN
            SET v_lapso_seg = genera_numero_aleatorio_rangos(10, 60);
        ELSE
            SET v_lapso_seg = genera_numero_aleatorio_rangos(61, 300);
        END IF;

    /* -------------------------
       TIPO: DURACION (1..110)  <-- pesos
       25 : 60-180s
       60 : 180-600s
       20 : 600-1800s
       5  : 1800-3600s
       ------------------------- */
    ELSEIF p_tipo = 'duracion' THEN
        SET v_roll = genera_numero_aleatorio_rangos(1, 110);

        IF v_roll <= 25 THEN
            SET v_lapso_seg = genera_numero_aleatorio_rangos(60, 180);
        ELSEIF v_roll <= 85 THEN -- 25 + 60
            SET v_lapso_seg = genera_numero_aleatorio_rangos(180, 600);
        ELSEIF v_roll <= 105 THEN -- 85 + 20
            SET v_lapso_seg = genera_numero_aleatorio_rangos(600, 1800);
        ELSE -- 106..110
            SET v_lapso_seg = genera_numero_aleatorio_rangos(1800, 3600);
        END IF;

    ELSE
        RETURN NULL; -- tipo inválido
    END IF;

    -- Calcular fecha/hora resultante
    SET v_result = DATE_ADD(p_fecha_base, INTERVAL v_lapso_seg SECOND);

    -- Regla: si se pasa de NOW(), regresar NULL (sesión quedará "activa" después por trigger)
    IF v_result > NOW() THEN
        RETURN NULL;
    END IF;

    RETURN v_result;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP FUNCTION IF EXISTS `genera_fechahora_rangos` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` FUNCTION `genera_fechahora_rangos`(v_min DATETIME, v_max DATETIME) RETURNS datetime
    NO SQL
BEGIN
    DECLARE v_seconds BIGINT;

    -- diferencia en segundos entre fechas
    SET v_seconds = TIMESTAMPDIFF(SECOND, v_min, v_max);

    RETURN DATE_ADD(
        v_min,
        INTERVAL FLOOR(RAND() * v_seconds) SECOND
    );
END ;;
DELIMITER ;
