CREATE DEFINER=`root`@`localhost` FUNCTION `genera_numero_aleatorio_rangos`(v_limite_inferior INT,v_limite_superior INT) RETURNS int
    DETERMINISTIC
BEGIN
  RETURN FLOOR(v_limite_inferior + (RAND() * (v_limite_superior
  - v_limite_inferior + 1)));
END ;;
