DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `simula_carritos`(
    IN p_cuantos INT,
    IN p_total_productos INT,
    IN p_categoria VARCHAR(100)
)
BEGIN
    DECLARE v_i INT DEFAULT 1;
    DECLARE v_j INT DEFAULT 0;
    DECLARE v_intentos INT DEFAULT 0;
    DECLARE v_max_intentos INT DEFAULT 200;

    DECLARE v_pivote INT DEFAULT 0;
    DECLARE v_sesion_id INT DEFAULT NULL;
    DECLARE v_carrito_id INT DEFAULT NULL;
    DECLARE v_divisa_id INT DEFAULT NULL;

    DECLARE v_fecha_inicio_sesion DATETIME DEFAULT NULL;
    DECLARE v_fecha_creacion_carrito DATETIME DEFAULT NULL;

    DECLARE v_total_productos_actual INT DEFAULT 0;
    DECLARE v_total_disponibles INT DEFAULT 0;

    DECLARE v_producto_id INT DEFAULT NULL;
    DECLARE v_precio_unitario DECIMAL(10,2) DEFAULT 0.00;
    DECLARE v_cantidad INT DEFAULT 1;

    DECLARE v_categoria_existe INT DEFAULT 0;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        RESIGNAL;
    END;

    IF p_cuantos IS NULL OR p_cuantos <= 0 THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'El número de carritos debe ser mayor a 0';
    END IF;

    IF p_categoria IS NOT NULL AND TRIM(p_categoria) <> '' THEN
        SELECT COUNT(*)
        INTO v_categoria_existe
        FROM categorias c
        WHERE c.nombre = p_categoria
          AND c.estatus = 'Activa';

        IF v_categoria_existe = 0 THEN
            SIGNAL SQLSTATE '45000'
            SET MESSAGE_TEXT = 'La categoría indicada no existe o no está activa';
        END IF;
    END IF;

    carritos_loop: WHILE v_i <= p_cuantos DO
        START TRANSACTION;

        SET v_j = 0;
        SET v_intentos = 0;
        SET v_producto_id = NULL;
        SET v_precio_unitario = 0.00;
        SET v_cantidad = 1;
        SET v_total_productos_actual = p_total_productos;

        IF v_total_productos_actual IS NULL OR v_total_productos_actual <= 0 THEN
            SET v_pivote = genera_numero_aleatorio_rangos(1, 100);

            IF v_pivote <= 45 THEN
                SET v_total_productos_actual = 1;
            ELSEIF v_pivote <= 70 THEN
                SET v_total_productos_actual = 2;
            ELSEIF v_pivote <= 85 THEN
                SET v_total_productos_actual = 3;
            ELSEIF v_pivote <= 93 THEN
                SET v_total_productos_actual = 4;
            ELSEIF v_pivote <= 97 THEN
                SET v_total_productos_actual = 5;
            ELSE
                SET v_total_productos_actual = genera_numero_aleatorio_rangos(6, 8);
            END IF;
        END IF;

        IF p_categoria IS NULL OR TRIM(p_categoria) = '' THEN
            SELECT COUNT(*)
            INTO v_total_disponibles
            FROM productos p
            WHERE p.estatus IN ('Activo', 'En existencia', 'Baja existencia');
        ELSE
            SELECT COUNT(DISTINCT p.id)
            INTO v_total_disponibles
            FROM productos p
            INNER JOIN productos_categorias pc
                ON pc.producto_id = p.id
               AND pc.estatus = 'Activo'
            INNER JOIN categorias c
                ON c.id = pc.categoria_id
            WHERE p.estatus IN ('Activo', 'En existencia', 'Baja existencia')
              AND c.nombre = p_categoria
              AND c.estatus = 'Activa';
        END IF;

        IF v_total_disponibles = 0 THEN
            ROLLBACK;
            SIGNAL SQLSTATE '45000'
            SET MESSAGE_TEXT = 'No hay productos disponibles para el filtro indicado';
        END IF;

        IF v_total_productos_actual > v_total_disponibles THEN
            SET v_total_productos_actual = v_total_disponibles;
        END IF;

        SET v_sesion_id = elige_sesion();
        SET v_divisa_id = elige_divisa();

        SELECT s.fecha_inicio
        INTO v_fecha_inicio_sesion
        FROM sesiones s
        WHERE s.id = v_sesion_id;

        SET v_fecha_creacion_carrito = COALESCE(v_fecha_inicio_sesion, NOW());

        INSERT INTO carritos (
            id,
            sesion_id,
            divisa_id,
            total_productos,
            monto_aproximado,
            fecha_creacion,
            fecha_actualizacion,
            estatus
        )
        VALUES (
            DEFAULT,
            v_sesion_id,
            v_divisa_id,
            0,
            0.00,
            v_fecha_creacion_carrito,
            NULL,
            DEFAULT
        );

        SET v_carrito_id = LAST_INSERT_ID();

        detalle_loop: WHILE v_j < v_total_productos_actual AND v_intentos < v_max_intentos DO
            SET v_intentos = v_intentos + 1;

            SET v_producto_id = NULL;
            SET v_precio_unitario = 0.00;

            IF p_categoria IS NULL OR TRIM(p_categoria) = '' THEN
                SELECT p.id, p.precio_menudeo
                INTO v_producto_id, v_precio_unitario
                FROM productos p
                WHERE p.estatus IN ('Activo', 'En existencia', 'Baja existencia')
                  AND NOT EXISTS (
                        SELECT 1
                        FROM carrito_detalle cd
                        WHERE cd.carrito_id = v_carrito_id
                          AND cd.producto_id = p.id
                  )
                ORDER BY RAND()
                LIMIT 1;
            ELSE
                SELECT p.id, p.precio_menudeo
                INTO v_producto_id, v_precio_unitario
                FROM productos p
                INNER JOIN productos_categorias pc
                    ON pc.producto_id = p.id
                   AND pc.estatus = 'Activo'
                INNER JOIN categorias c
                    ON c.id = pc.categoria_id
                WHERE p.estatus IN ('Activo', 'En existencia', 'Baja existencia')
                  AND c.nombre = p_categoria
                  AND c.estatus = 'Activa'
                  AND NOT EXISTS (
                        SELECT 1
                        FROM carrito_detalle cd
                        WHERE cd.carrito_id = v_carrito_id
                          AND cd.producto_id = p.id
                  )
                ORDER BY RAND()
                LIMIT 1;
            END IF;

            IF v_producto_id IS NULL THEN
                LEAVE detalle_loop;
            END IF;

            SET v_cantidad = elige_cantidad();

            INSERT INTO carrito_detalle (
                carrito_id,
                producto_id,
                cantidad,
                precio_unitario,
                fecha_registro,
                fecha_actualizacion,
                estatus
            )
            VALUES (
                v_carrito_id,
                v_producto_id,
                v_cantidad,
                v_precio_unitario,
                v_fecha_creacion_carrito,
                NULL,
                'Activo'
            );

            SET v_j = v_j + 1;
        END WHILE detalle_loop;

        UPDATE carritos c
        JOIN (
            SELECT 
                cd.carrito_id,
                IFNULL(SUM(cd.cantidad), 0) AS total_productos,
                IFNULL(ROUND(SUM(cd.cantidad * cd.precio_unitario), 2), 0.00) AS monto_aproximado
            FROM carrito_detalle cd
            WHERE cd.carrito_id = v_carrito_id
              AND cd.estatus = 'Activo'
            GROUP BY cd.carrito_id
        ) x
            ON c.id = x.carrito_id
        SET 
            c.total_productos = x.total_productos,
            c.monto_aproximado = x.monto_aproximado
        WHERE c.id = v_carrito_id;

        COMMIT;
        SET v_i = v_i + 1;
    END WHILE carritos_loop;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `simula_carritos_sunombre` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
