DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `simula_carritos_sunombre`(v_cuantos INT, v_total_productos INT, 
v_categoria VARCHAR(50))
BEGIN
	DECLARE i INT DEFAULT 1;
    DECLARE j INT DEFAULT 1;
    DECLARE v_carrito_id INT DEFAULT NULL;
    DECLARE v_pivote INT DEFAULT 0;
    DECLARE v_sesion_id INT DEFAULT NULL;
	DECLARE v_fecha_inicio_sesion DATETIME DEFAULT NULL;
    DECLARE v_fecha_fin_sesion DATETIME DEFAULT NULL;
    DECLARE v_precio_fijo DECIMAL(10,2) DEFAULT 0.0;
    DECLARE v_producto_id INT DEFAULT NULL;
    
    
      	WHILE i <= v_cuantos DO
          START TRANSACTION;
			-- VALIDAR QUE EL NUMERO DE PRODUCTOS NO SEA NULO, EN CASO DE NULO ASIGNAR 
            -- EL TOTAL EN BASE A LOS PORCENTAJES DEFINIDOS
            IF v_total_productos IS NULL  OR v_total_productos=0 THEN 
               SET v_pivote=genera_numero_aleatorio_rangos(0,100);   
			   -- Distribución boutique:
               -- 1:45%, 2:25%, 3:15%, 4:8%, 5:4%, 6-8:3%
				IF v_pivote <= 45 THEN
                SET v_total_productos = 1;
				ELSEIF v_pivote <= 70 THEN
                SET v_total_productos = 2;
				ELSEIF v_pivote <= 85 THEN
                SET v_total_productos = 3;
				ELSEIF v_pivote <= 93 THEN
                SET v_total_productos = 4;
				ELSEIF v_pivote <= 97 THEN
                SET v_total_productos = 5;
				ELSE
                SET v_total_productos = genera_numero_aleatorio_rangos(6, 15);
            END IF;
        END IF;
          
            -- FASE 1: SIMULACION DE LOS DATOS DEL CARRITO
            SET v_sesion_id = elige_sesion();
            SET v_fecha_inicio_sesion= (SELECT fecha_inicio FROM sesiones WHERE id = v_sesion_id);
            SET v_fecha_fin_sesion= (SELECT fecha_fin FROM sesiones WHERE id = v_sesion_id);
            
			INSERT INTO carritos VALUES(
			DEFAULT, v_sesion_id, elige_divisa() , v_total_productos, 
            DEFAULT, v_fecha_inicio_sesion , null, DEFAULT);
			SET i= i+1;
            
            SET v_carrito_id = last_insert_id();
            -- FASE 2: SIMULACION DE LOS DETALLES DEL CARRITO
            
            WHILE j <= v_total_productos DO
              SET v_producto_id = elige_producto(v_categoria);
			  SET v_precio_fijo = (SELECT precio_menudeo FROM productos 
              WHERE id = v_producto_id);
              INSERT carrito_detalle VALUES (v_carrito_id, v_producto_id, 
              elige_cantidad(), v_precio_fijo,
              genera_fechahora_rangos(v_fecha_inicio_sesion, v_fecha_fin_sesion), null, default);
			  SET j=j+1;
			END WHILE;
            
		           
			COMMIT;
		END WHILE;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
