CREATE DEFINER=`root`@`localhost` PROCEDURE `simula_compras`(
    IN p_cuantos INT,
    IN p_pedido_inicio INT,
    IN p_pedido_fin INT
)
BEGIN
    DECLARE v_i INT DEFAULT 1;

    DECLARE v_pedido_id INT;
    DECLARE v_metodo_pago_id INT;

    DECLARE v_monto DECIMAL(10,2);
    DECLARE v_origen VARCHAR(50);

    DECLARE v_rand DECIMAL(5,4);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
    END;

    carritos_loop: WHILE v_i <= p_cuantos DO

        START TRANSACTION;

        SET v_pedido_id = FLOOR(
            p_pedido_inicio + RAND() * (p_pedido_fin - p_pedido_inicio + 1)
        );

        SELECT importe_total
        INTO v_monto
        FROM pedidos
        WHERE id = v_pedido_id
        LIMIT 1;

        --  VALIDACIÓN
        IF v_monto IS NULL THEN
            ROLLBACK;
            SET v_i = v_i + 1;
            ITERATE carritos_loop;
        END IF;

        --  ORIGEN DE PAGO
        SET v_rand = RAND();

        IF v_rand <= 0.50 THEN
            SET v_origen = 'Tarjeta';
        ELSEIF v_rand <= 0.75 THEN
            SET v_origen = 'PayPal';
        ELSE
            SET v_origen = 'Transferencia';
        END IF;

        --  MÉTODO DE PAGO
        INSERT INTO metodos_pago (
            origen,
            estatus
        )
        VALUES (
            v_origen,
            'Activo'
        );

        SET v_metodo_pago_id = LAST_INSERT_ID();

        --  TRANSACCIÓN FINANCIERA
        INSERT INTO transacciones_financieras (
            pedido_id,
            metodo_pago_id,
            importe,
            fecha_pago,
            estatus
        )
        VALUES (
            v_pedido_id,
            v_metodo_pago_id,
            v_monto,
            NOW(),
            'Aprobado'
        );

        COMMIT;

        SET v_i = v_i + 1;

    END WHILE carritos_loop;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
