CREATE DEFINER=`root`@`localhost` PROCEDURE `simula_pedido`( v_carrito_id INT)
BEGIN
	
    DECLARE v_total_productos INT DEFAULT 
    (SELECT total_productos FROM carritos WHERE id = v_carrito_id); 
    -- No hay perdida de productos
    
    DECLARE v_importe_total DECIMAL(10,2) DEFAULT (SELECT monto_aproximado 
    FROM carritos  WHERE id = v_carrito_id);   -- El precio se mantiene
       
	INSERT INTO pedidos VALUES(DEFAULT,v_carrito_id,v_total_productos,
    v_importe_total,DEFAULT,null,"Pendiente",b'1');  
    -- Las fechas deberán ser corregidas para el examen práctico
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `simula_sesiones` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
