DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `simula_sesiones`(v_cuantos INT)
BEGIN
	DECLARE i INT DEFAULT 1;
    DECLARE v_dispositivo VARCHAR(50) DEFAULT NULL;
    DECLARE v_fecha_apertura_ecommerce DATETIME DEFAULT "2020-01-01 00:00:00";
    DECLARE v_fecha_hoy DATETIME DEFAULT NOW();
    DECLARE v_fecha_registro DATETIME DEFAULT NULL;
    
	WHILE i <= v_cuantos DO
        SELECT CONCAT_ws(" ", "Simulando la sesión :",i) as mensaje; 
        SET v_dispositivo = elige_dispositivo();
        SET v_fecha_registro =genera_fechahora_rangos(v_fecha_apertura_ecommerce, v_fecha_hoy);
		
        INSERT INTO sesiones VALUES (DEFAULT,elige_usuario(),
        elige_plataforma(), v_dispositivo,elige_sistema_operativo(v_dispositivo),
        elige_pais(),v_fecha_registro,
        genera_fechahora_lapso(v_fecha_registro, "demora"),genera_fechahora_lapso(v_fecha_registro, "duracion"),"Activa"); 
		SET i= i+1;
	END WHILE;
END ;;
DELIMITER ;
